        this.NodeManager.closeDropdowns();

        const selection = this.Utilities.getSelection() || window.getSelection();
        const range = document.createRange();
        range.selectNode(image);
        selection.removeAllRanges();
        selection.addRange(range);
        this.savedSelection = this.Utilities.saveSelection(selection);
        this.ImageDialog.openImageDialogForElement(image, range);
