const insertBlockOutsideContainer = (range, block, content) => {
    if (!range || !block || !content) return false;

    range.deleteContents();

    const marker = document.createComment('rtb-block-insertion');
    range.insertNode(marker);

    let topLevel = marker;
    while (topLevel.parentNode && topLevel.parentNode !== content) {
        topLevel = topLevel.parentNode;
    }

    if (!topLevel || (topLevel !== marker && topLevel.parentNode !== content)) {
        marker.remove();
        return false;
    }

    const canSplit = topLevel.nodeType === Node.ELEMENT_NODE &&
        /^(P|H1|H2|H3|H4|H5|H6)$/.test(topLevel.nodeName);

    if (canSplit) {
        const trailingBlock = topLevel.cloneNode(false);
        const trailingRange = document.createRange();
        trailingRange.setStartAfter(marker);
        trailingRange.setEnd(topLevel, topLevel.childNodes.length);
        trailingBlock.appendChild(trailingRange.extractContents());
        marker.remove();

        topLevel.parentNode.insertBefore(block, topLevel.nextSibling);
        if (trailingBlock.textContent.trim() !== '' ||
            trailingBlock.querySelector('br, img, video, audio, object, table, hr')) {
            block.parentNode.insertBefore(trailingBlock, block.nextSibling);
        }

        if (topLevel.textContent.trim() === '' &&
            !topLevel.querySelector('br, img, video, audio, object, table, hr')) {
            topLevel.remove();
        }
    }
    else if (topLevel === marker) {
        marker.replaceWith(block);
    }
    else {
        marker.remove();
        topLevel.parentNode.insertBefore(block, topLevel.nextSibling);
    }

    return true;
};

