    // ---- Color dialogs -----------------------------------------------------

    _colorSwatches(selectMethod) {
        const neutrals = [
            '#000000','#101010','#202020','#303030','#404040','#555555','#6A6A6A','#7F7F7F',
            '#949494','#A8A8A8','#BDBDBD','#D0D0D0','#E0E0E0','#EDEDED','#F7F7F7','#FFFFFF',
        ];
        const hues = [0, 12, 24, 36, 48, 60, 90, 120, 150, 180, 205, 230, 255, 280, 305, 330];
        const lightness = [80, 68, 56, 44, 32, 20];
        const hslToHex = (h, s, l) => {
            s /= 100;
            l /= 100;
            const chroma = (1 - Math.abs(2 * l - 1)) * s;
            const segment = h / 60;
            const secondary = chroma * (1 - Math.abs(segment % 2 - 1));
            const offset = l - chroma / 2;
            const rgb = segment < 1 ? [chroma, secondary, 0]
                : segment < 2 ? [secondary, chroma, 0]
                : segment < 3 ? [0, chroma, secondary]
                : segment < 4 ? [0, secondary, chroma]
                : segment < 5 ? [secondary, 0, chroma]
                : [chroma, 0, secondary];
            return `#${rgb.map(value =>
                Math.round((value + offset) * 255).toString(16).padStart(2, '0')
            ).join('').toUpperCase()}`;
        };
        const colors = lightness.flatMap(level =>
            hues.map(hue => hslToHex(hue, 85, level))
        ).concat(neutrals);
        return colors.map(c =>
            `<div class="blazing-rich-text-color-option" role="option" aria-label="${c}" title="${c}" data-color="${c}" onclick="RTNative_Method('${selectMethod}','${this._uid}','${c}')" style="background-color:${c};"></div>`
        ).join('');
    }

